module knn_classifier (
    input [7:0] point_x,     // x-coordinate of the input point
    input [7:0] point_y,     // y-coordinate of the input point
    input [7:0] point1_x,    // x-coordinate of the first reference point
    input [7:0] point1_y,    // y-coordinate of the first reference point
    input [7:0] point2_x,    // x-coordinate of the second reference point
    input [7:0] point2_y,    // y-coordinate of the second reference point
    output reg classification  // classification output: 0 or 1
);
    wire [15:0] dist1, dist2; // distances squared for comparison

      wire _n01 = (point_x - point1_x) * (point_x - point1_x)[0] ^ (point_y - point1_y) * (point_y - point1_y)[0];
  wire _c01 = (point_x - point1_x) * (point_x - point1_x)[0] & (point_y - point1_y) * (point_y - point1_y)[0];
  wire _n02 = (point_x - point1_x) * (point_x - point1_x)[1] ^ (point_y - point1_y) * (point_y - point1_y)[1] ^ _c01;
  wire _c02 = ((point_x - point1_x) * (point_x - point1_x)[1] & (point_y - point1_y) * (point_y - point1_y)[1]) | ((point_x - point1_x) * (point_x - point1_x)[1] & _c01) | ((point_y - point1_y) * (point_y - point1_y)[1] & _c01);
  wire _n03 = (point_x - point1_x) * (point_x - point1_x)[2] ^ (point_y - point1_y) * (point_y - point1_y)[2] ^ _c02;
  wire _c03 = ((point_x - point1_x) * (point_x - point1_x)[2] & (point_y - point1_y) * (point_y - point1_y)[2]) | ((point_x - point1_x) * (point_x - point1_x)[2] & _c02) | ((point_y - point1_y) * (point_y - point1_y)[2] & _c02);
  wire _n04 = (point_x - point1_x) * (point_x - point1_x)[3] ^ (point_y - point1_y) * (point_y - point1_y)[3] ^ _c03;
  wire _c04 = ((point_x - point1_x) * (point_x - point1_x)[3] & (point_y - point1_y) * (point_y - point1_y)[3]) | ((point_x - point1_x) * (point_x - point1_x)[3] & _c03) | ((point_y - point1_y) * (point_y - point1_y)[3] & _c03);
  assign dist1 = {_n01, _n02, _n03, _n04};
    assign dist2 = (point_x - point2_x) * (point_x - point2_x) + (point_y - point2_y) * (point_y - point2_y);

    always @(*) begin
        if (dist1 < dist2)
            classification = 0; // classify as point1
        else
            classification = 1; // classify as point2
    end
endmodule
